---@class LFightFormationData
local LFightFormationData = classX("LFightFormationData", nil)
function LFightFormationData:ctor()
    ---@type string  玩家唯一ID(怪物阵型则为0)
    self.playerId = ""
    ---@type number 阵型refId
    self.refId = 0
    ---@type number 是否怪物表 0否 1是
    self.monster = false
    ---@type table<string, LBattleUnitGridData> <id,data>英雄站位
    self.grids = {}
    ---@type number 阵容战力
    self.power = 0
    ---@type boolean 是否是机器人
    self.robot = false
    ---@type number mvp的战斗单位id
    self.mvpHeroRefId = 0
    ---@type string mvp的英雄Id int64-> string
    self.mvpHeroId = ""
    ---@type table<string, LBattleFreeUnitData>  <id,data> 自由战斗单位数据集合（宝物、神器等...）
    self.combatUnits = {}
    ---@type number 怪物阵容refId
    self.monsterFormationRefId = 0
    ---@type string 阵容名称
    self.formationName = ""
    ---@type number  战术
    self.tactics = 0

    self.teamType = BattleTeamSide.teamNone
end

function LFightFormationData:ToJsonTable()
    local jsonTab = {}
    jsonTab.playerId = self.playerId
    jsonTab.refId = self.refId
    jsonTab.monster = self.monster and 1 or 0
    jsonTab.grids = {}
    for i, v in pairs(self.grids) do
        table.insert(jsonTab.grids, v:ToJsonTable())
    end
    jsonTab.power = self.power
    jsonTab.robot = self.robot and 1 or 0
    jsonTab.mvpHeroRefId = self.mvpHeroRefId
    jsonTab.mvpHeroId = self.mvpHeroId

    jsonTab.combatUnits = {}
    for i, v in pairs(self.combatUnits) do
        table.insert(jsonTab.combatUnits, v:ToJsonTable())
    end
    jsonTab.monsterFormationRefId = self.monsterFormationRefId
    jsonTab.formationName = self.formationName
    jsonTab.tactics = self.tactics
    return jsonTab
end

function LFightFormationData:InitData(fromData, teamType)
    self.teamType = teamType

    self.playerId = fromData.playerId
    self.monster = fromData.monster == 1

    self.grids = {}

    local grids = fromData.grids
    if grids then
        for i, heroGrid in ipairs(grids) do
            self:AddBattleHeroGrid(heroGrid, teamType)
        end
    end

    self.power = fromData.power
    self.robot = fromData.robot == 1

    self.combatUnits = {}
    local combatUnits = fromData.combatUnits
    if combatUnits then
        for i, unit in ipairs(combatUnits) do
            self:AddBattleUnit(unit)
        end
    end

    self.mvpHeroRefId = fromData.mvpHeroRefId
    self.mvpHeroId = tostring(fromData.mvpHeroId)

    self.monsterFormationRefId = fromData.monsterFormationRefId
    self.formationName = fromData.formationName
    self.tactics = fromData.tactics
end

function LFightFormationData:AddBattleHeroGrid(gridData, teamType)
    local id = tostring(gridData.id)
    ---@type LBattleUnitGridData
    local heroGrid = self.grids[id]
    if not heroGrid then
        heroGrid =  require("LApp.gameplay.videobattle.data.LBattleUnitGridData"):new()
        self.grids[id] = heroGrid
    end
    heroGrid:InitData(gridData, teamType)
end

function LFightFormationData:AddBattleUnit(unitData)
    local id = tostring(unitData.id)
    ---@type LBattleFreeUnitData
    local unit = self.combatUnits[id]
    if not unit then
        unit =  require("LApp.gameplay.videobattle.data.LBattleFreeUnitData"):new()
        self.combatUnits[id] = unit
    end
    unit:InitData(unitData)
    return unit
end

return LFightFormationData